3_real_world_example.code:
//  Old Callback Approach (Inversion of Control)
function getUserCB(id, callback) {
  setTimeout(() => callback(null, { id, name: 'Alice' }), 1000);
}
getUserCB(1, (err, user) => {
  console.log('Callback got:', user);
});

//  Modern Promise Approach (You keep control)
function getUserPromise(id) {
  return new Promise((resolve, reject) => {
    setTimeout(() => resolve({ id, name: 'Alice' }), 1000);
  });
}
const userPromise = getUserPromise(1);
userPromise.then(user => {
  console.log('Promise got:', user);
});

6_edge_case.code:
console.log('1');
new Promise((resolve) => {
  console.log('2'); // Runs synchronously!
  resolve();
}).then(() => console.log('4')); // Runs asynchronously (microtask)
console.log('3');
// Output: 1, 2, 3, 4
